#!/usr/bin/env python3
"""
Agrega logs de depuracion al bot de WhatsApp (incluye el fix anterior
de no confirmar citas si la herramienta devuelve error). Cada llamada
a una herramienta (check_availability, book_appointment, etc.) y cada
respuesta final sin herramienta quedan registradas con console.log,
visibles en Vercel > tu proyecto > Logs, buscando '[whatsapp-bot]'.

Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_whatsapp_bot_debug_logs.py
"""

import base64
from pathlib import Path

WHATSAPP_BOT_B64 = """"""

def main():
    p = Path("src/lib/whatsappBot.ts")
    p.write_bytes(base64.b64decode(WHATSAPP_BOT_B64))
    print(f"escrito: {p} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Bot de WhatsApp: logs de depuracion + no confirmar en error'")
    print("  git push")

if __name__ == "__main__":
    main()